mapper.insert:
		/*
             SQL ID : QstnVwitmDAO.qstnVwitmBulkRegist
             설  명 : 문항보기항목일괄등록
         */
         INSERT ALL

			INTO TB_LMS_QSTN_VWITM (
	         	  QSTN_VWITM_ID
				, QSTN_ID
				, QSTN_VWITM_GBNCD
				, QSTN_VWITM_CTS
				, CRANS_YN
				, QSTN_VWITM_SEQNO
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.qstnVwitmId}
				, #{item.qstnId}
				, #{item.qstnVwitmGbncd}
				, #{item.qstnVwitmCts}
				, #{item.cransYn}
				, #{item.qstnVwitmSeqno}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : QstnVwitmDAO.qstnVwitmDelete
             설  명 : 문항보기항목삭제
         */
         DELETE FROM TB_LMS_QSTN_VWITM
          WHERE QSTN_ID = #{qstnId}
